import { serve } from "bun";

const PORT = 58247;
const WEBHOOK_URL = process.env.WEBHOOK_URL || "";

if (!WEBHOOK_URL) {
  console.error("ERROR: WEBHOOK_URL environment variable is not set");
  process.exit(1);
}

// Serve the HTML file
async function serveHtml() {
  const file = Bun.file("index.html");
  return new Response(file, {
    headers: {
      "Content-Type": "text/html",
    },
  });
}

// Handle POST request to /api/contact
async function handleContact(req: Request) {
  try {
    const body = await req.json();

    // Validate required fields
    if (!body.name || !body.email) {
      return new Response(
        JSON.stringify({ error: "Name and email are required" }),
        {
          status: 400,
          headers: { "Content-Type": "application/json" },
        }
      );
    }

    // Add timestamp
    const data = {
      ...body,
      timestamp: new Date().toISOString(),
    };

    // Send to webhook
    const webhookResponse = await fetch(WEBHOOK_URL, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify(data),
    });

    if (webhookResponse.ok) {
      return new Response(
        JSON.stringify({ success: true, message: "Thank you! We'll be in touch soon." }),
        {
          status: 200,
          headers: { "Content-Type": "application/json" },
        }
      );
    } else {
      throw new Error("Webhook submission failed");
    }
  } catch (error) {
    console.error("Error handling contact form:", error);
    return new Response(
      JSON.stringify({ error: "Something went wrong. Please try again." }),
      {
        status: 500,
        headers: { "Content-Type": "application/json" },
      }
    );
  }
}

// Start server
serve({
  port: PORT,
  async fetch(req) {
    const url = new URL(req.url);
    const method = req.method;

    // Serve HTML for root path
    if (url.pathname === "/" && (method === "GET" || method === "HEAD")) {
      if (method === "HEAD") {
        return new Response(null, {
          headers: {
            "Content-Type": "text/html",
          },
        });
      }
      return serveHtml();
    }

    // Handle contact form submission
    if (url.pathname === "/api/contact" && method === "POST") {
      return handleContact(req);
    }

    // 404 for other routes
    return new Response("Not Found", { status: 404 });
  },
});

console.log(`🚀 Server running at http://localhost:${PORT}`);

